import "./tarjeta.css";

function Tarjeta([ruta, titulo, descripcion]) {


    return (
        <div className="tarjeta">
            <img src={ruta} alt="Logo" />
            <div className="texto-tarjeta" >
                <h3>{titulo}</h3>
                <p>{descripcion}</p>
            </div>
        </div>
    );
};

export default Tarjeta;
